import{_ as a,o,c as t,ae as i}from"./chunks/framework.Co1PSFSm.js";const r="/assets/image-3.kIlbMeJn.png",l="/assets/image-4.C0FbD5vL.png",s="/assets/image-6.DgNOJv2W.png",n="/assets/image-2.CiRScShv.png",k=JSON.parse('{"title":"MineBook Hot Server：个人开发的本地服务智能管理工具","description":"","frontmatter":{},"headers":[],"relativePath":"blog/开发了一个APP，我叫它minebook-hot-server.md","filePath":"blog/开发了一个APP，我叫它minebook-hot-server.md","lastUpdated":1778811107000}'),p={name:"blog/开发了一个APP，我叫它minebook-hot-server.md"};function h(c,e,d,_,m,u){return o(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="minebook-hot-server-个人开发的本地服务智能管理工具" tabindex="-1">MineBook Hot Server：个人开发的本地服务智能管理工具 <a class="header-anchor" href="#minebook-hot-server-个人开发的本地服务智能管理工具" aria-label="Permalink to &quot;MineBook Hot Server：个人开发的本地服务智能管理工具&quot;">​</a></h1><p><strong>MineBook Hot Server</strong> 是我个人开发的一款用于管理本地开发服务的自动化工具，用于智能监控和管理本地端口，有效减少不必要的系统资源占用。</p><h2 id="背景与需求" tabindex="-1">背景与需求 <a class="header-anchor" href="#背景与需求" aria-label="Permalink to &quot;背景与需求&quot;">​</a></h2><p>在我日常的开发工作中，我遇到了一些痛点：</p><ul><li>本地服务端口被占用时，我很难快速定位是哪个进程在运行</li><li>偶尔启动的服务在使用完毕后，我经常会忘记手动关闭</li><li>这些未关闭的服务导致我的电脑内存压力一直很高</li><li>长期下来，我的 MacBook 就会因为内存不足而变得卡顿</li><li>当内存不足时，MacBook 会启用虚拟内存，将硬盘作为交换空间，这样会影响硬盘寿命</li></ul><p>我相信其他开发者也可能面临类似的困扰。</p><h2 id="个人解决方案" tabindex="-1">个人解决方案 <a class="header-anchor" href="#个人解决方案" aria-label="Permalink to &quot;个人解决方案&quot;">​</a></h2><p>基于上述的痛点，作为一个程序员，当然是写个APP来解决咯~</p><p>于是，我设计并开发了 <strong>MineBook Hot Server</strong> 来解决我自己遇到的这些问题。</p><p>该工具基于 Tauri 构建，采用 Rust 作为后端语言，前端使用 Web 技术实现。核心技术方案如下：</p><ul><li>后台轮询监听端口流量：系统定期扫描指定端口的流量情况</li><li>活跃度判断：通过检测端口流量变化来判断服务是否处于活跃状态</li><li>智能关闭：如果端口在设定时间内（如30秒）没有流量变化，则判定为不活跃</li><li>进程管理：对不活跃的端口进行 PID 反查，并自动发送终止命令</li></ul><h2 id="界面一览" tabindex="-1">界面一览 <a class="header-anchor" href="#界面一览" aria-label="Permalink to &quot;界面一览&quot;">​</a></h2><h3 id="主页" tabindex="-1">主页 <a class="header-anchor" href="#主页" aria-label="Permalink to &quot;主页&quot;">​</a></h3><p><img src="'+r+'" alt="alt text"></p><p>主页目前提供了基本上所有的功能：</p><ul><li>添加服务：添加新的服务，并保存配置</li><li>修改服务：修改已添加的服务配置</li><li>删除服务：删除已添加的服务</li><li>启动服务：点击端口号即可启动已添加的服务</li><li>停止服务：停止已添加的服务</li><li>复制服务：复制服务启动命令，方便快速创建新的服务端口代理</li><li>端口详情：查看服务详情，包括启动命令、端口号、服务状态、服务创建时间、闲置时间、运行状态、进程ID（PID）</li></ul><h3 id="添加服务弹窗" tabindex="-1">添加服务弹窗 <a class="header-anchor" href="#添加服务弹窗" aria-label="Permalink to &quot;添加服务弹窗&quot;">​</a></h3><p><img src="'+l+'" alt="alt text"></p><p>弹窗比较简单，输入必备的服务信息，点击&quot;创建服务&quot;按钮即可完成服务添加。</p><h3 id="监听端口进程" tabindex="-1">监听端口进程 <a class="header-anchor" href="#监听端口进程" aria-label="Permalink to &quot;监听端口进程&quot;">​</a></h3><p><img src="'+s+'" alt="alt text"></p><p>这个页面是一个端口的快速查看页面，能查看当前系统中已经启动的端口服务。</p><p>也能看到哪些端口已经被minebook-hot-server托管，</p><p>未托管的端口，可以点击”托管“按钮，快速的完成端口托管。</p><h3 id="后台日志页" tabindex="-1">后台日志页 <a class="header-anchor" href="#后台日志页" aria-label="Permalink to &quot;后台日志页&quot;">​</a></h3><p><img src="'+n+'" alt="alt text"></p><p>这是一个后台的日志，如果遇到问题可以快速定位。</p><p>对于非开发人员估计用不上。</p><h2 id="个人开发总结" tabindex="-1">个人开发总结 <a class="header-anchor" href="#个人开发总结" aria-label="Permalink to &quot;个人开发总结&quot;">​</a></h2><p><strong>MineBook Hot Server</strong> 是我独立设计和实现的项目。从概念设计到功能实现，再到实际部署，整个项目完全由我个人完成。经过一段时间的实际使用验证，该工具在以下方面表现出色：</p><ul><li>有效控制内存占用</li><li>清晰展示当前活跃的本地端口信息</li><li>基于 RAS 架构，保证了系统的稳定性</li></ul><p>如果你也常常为本地服务管理而烦恼，不妨关注我的技术分享，了解这款工具的最新进展。我正在持续优化中，未来版本将增加更多实用功能。欢迎试用并提出宝贵意见，帮助我进一步完善这个工具！</p>',32)])])}const P=a(p,[["render",h]]);export{k as __pageData,P as default};
